<?php namespace App\Repositories\Transport;use App\Repositories\BaseRepository;use App\Models\Transport\TransportAllocation;use Illuminate\Database\Eloquent\Collection;class TransportAllocationRepository extends BaseRepository{    public function __construct(TransportAllocation $model)    {        $this->model = $model;        parent::__construct($model);    }    public function findByStudent(int $studentId): Collection    {        return $this->findByField('student_id', $studentId);    }    public function findByRoute(int $routeId): Collection    {        return $this->findByField('transport_route_id', $routeId);    }    public function findByVehicle(int $vehicleId): Collection    {        return $this->findByField('vehicle_id', $vehicleId);    }    public function findByStatus(string $status): Collection    {        return $this->findByField('status', $status);    }    public function getActiveAllocations(): Collection    {        return $this->query()->where('status', 'active')->get();    }    public function getByAcademicYear(int $academicYearId): Collection    {        return $this->findByField('academic_year_id', $academicYearId);    }    public function allocateStudent(int $studentId, int $routeId, int $vehicleId, array $data = []): TransportAllocation    {        $data['student_id'] = $studentId;        $data['transport_route_id'] = $routeId;        $data['vehicle_id'] = $vehicleId;        $data['status'] = 'active';        return $this->create($data);    }    public function deallocateStudent(int $allocationId): bool    {        return $this->update($allocationId, [            'status' => 'ended',            'ended_at' => now(),        ]);    }    public function getByPickupStop(string $stop): Collection    {        return $this->findByField('pickup_point', $stop);    }    public function countByRoute(): Collection    {        return $this->query()->selectRaw('transport_route_id, COUNT(*) as total')->where('status', 'active')->groupBy('transport_route_id')->get();    }}